const validarDadosUsuario=(nome,email,senha)=>{if(nome){const valNome=limparVal(nome.value);if(!validarCampoObrigatorio(nome,valNome,50)){return definirRetorno(!0,"O nome é obrigatório e deve ter no máximo 50 caracteres. Por favor, tente novamente.",nome)}}
const valEmail=limparVal(email.value);const valSenha=limparVal(senha.value);const expRegEmail=new RegExp(/^[\w+%.\-]+@[\w+%.\-]+\.[a-zA-Z\d]{2,}$/);const expRegSenha=new RegExp(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[^\w\d\s]).{8,30}$/);if(!validarCampo(email)||!expRegEmail.test(valEmail)||valEmail.length>80){return definirRetorno(!0,"O e-mail é obrigatório, deve ser válido (nome@exemplo.br) e ter no máximo 80 caracteres. Por favor, tente novamente.",email)}
if(!validarCampo(senha)||!expRegSenha.test(valSenha)){return definirRetorno(!0,"A senha é obrigatória e deve ter entre 8 e 30 caracteres, incluindo uma letra minúscula, uma letra maiúscula, um número e um símbolo. Por favor, tente novamente.",senha)}
return definirRetorno()};const definirRetorno=(deuErro=!1,msg="",campo=null)=>{return{estadoErro:deuErro,msgErro:msg,campoErro:campo}};const limparVal=(val)=>val.trim();const validarCampoObrigatorio=(campo,valCampo,qtdCarac)=>validarCampo(campo)&&valCampo!==""&&valCampo.length<=qtdCarac;const validarCampo=(campo)=>campo.checkValidity();const limparCampo=(campo)=>{campo.value="";if(window.innerWidth>=992)campo.focus();};const converterNum=(val)=>Number(val);const validarId=(valId)=>Number.isInteger(valId)&&valId>=1